<template><div class="panel"><div class="section-head"><div><h2>部门管理</h2><p>部门树用于用户归属和数据权限。</p></div><el-button v-if="auth.hasPermission('system:department:create')" type="primary" @click="open()">新增部门</el-button></div><el-table :data="treeRows" row-key="id" default-expand-all><el-table-column prop="name" label="名称"/><el-table-column prop="code" label="编码"/><el-table-column prop="sortOrder" label="排序"/><el-table-column label="操作"><template #default="s"><el-button link @click="open(null,s.row.id)">新增下级</el-button><el-button link type="primary" @click="open(s.row)">编辑</el-button><el-button link type="danger" @click="remove(s.row)">删除</el-button></template></el-table-column></el-table><el-dialog v-model="visible" :title="form.id?'编辑部门':'新增部门'"><el-form label-width="90px"><el-form-item label="上级"><el-select v-model="form.parentId" clearable><el-option v-for="item in rows" :key="item.id" :label="item.name" :value="item.id"/></el-select></el-form-item><el-form-item label="编码"><el-input v-model="form.code"/></el-form-item><el-form-item label="名称"><el-input v-model="form.name"/></el-form-item><el-form-item label="排序"><el-input-number v-model="form.sortOrder"/></el-form-item><el-form-item label="启用"><el-switch v-model="form.enabled"/></el-form-item></el-form><template #footer><el-button @click="visible=false">取消</el-button><el-button type="primary" @click="save">保存</el-button></template></el-dialog></div></template>
<script setup>import {computed,onMounted,reactive,ref} from 'vue';import {ElMessage,ElMessageBox} from 'element-plus';import http from '../api/http';import {useAuthStore} from '../stores/auth';import {buildTree} from '../utils/tree';const auth=useAuthStore(),rows=ref([]),visible=ref(false),treeRows=computed(()=>buildTree(rows.value)),form=reactive({id:null,parentId:null,code:'',name:'',sortOrder:0,enabled:true});async function load(){rows.value=(await http.get('/system/departments')).data}/** 打开部门窗口。 */function open(row,parentId){Object.assign(form,row?{...row}:{id:null,parentId:parentId||null,code:'',name:'',sortOrder:0,enabled:true});visible.value=true}/** 保存部门。 */async function save(){form.id?await http.put(`/system/departments/${form.id}`,form):await http.post('/system/departments',form);visible.value=false;await load();ElMessage.success('保存成功')}/** 删除部门。 */async function remove(row){await ElMessageBox.confirm(`确认删除部门「${row.name}」？`,'删除确认',{type:'warning'});await http.delete(`/system/departments/${row.id}`);await load()}onMounted(load)</script>
